// ūüĒī TRATAMENTO DE ERRO DO AGENTE
if (items[0].json.error) {
  return [{
    json: {
      resposta: "Opa, parece que algo deu errado e n√£o consegui processar a sua mensagem. Poderia me explicar melhor?",
      url_img: null,
      tipo: "erro_agente"
    }
  }];
}

let final;
try {
  let rawOutput = items[0].json.output;

  // =========================
  // ūüß† NORMALIZA ENTRADA
  // =========================
  if (typeof rawOutput !== 'string') {
    rawOutput = JSON.stringify(rawOutput);
  }
  rawOutput = rawOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  // =========================
  // ūüß† DESERIALIZA JSON MULTI-CAMADA
  // =========================
  for (let i = 0; i < 5; i++) {
    try {
      const parsed = JSON.parse(rawOutput);
      if (typeof parsed === 'string') {
        rawOutput = parsed;
      } else {
        rawOutput = parsed;
        break;
      }
    } catch {
      break;
    }
  }

  // =========================
  // ūüüĘ CASO: J√Ā √Č OBJETO JSON COM resposta + url_img
  // =========================
  if (typeof rawOutput === 'object' && rawOutput !== null) {
    final = {
      resposta: rawOutput.resposta || null,
      url_img: rawOutput.url_img || null,
      tipo: "json_limpo"
    };
  } else {
    let resposta = String(rawOutput);
    let url_img = null;

    // =========================
    // ūüĒć ENCONTRA A URL DO IMAGE-CHARTS (QUALQUER FORMATO)
    // Estrat√©gia: achar onde come√ßa a URL, pegar tudo at√© o √ļltimo %7D
    // Isso evita problemas com par√™nteses dentro da URL (rgba, etc.)
    // =========================
    const URL_MARKER = 'https://image-charts.com';
    const urlStart = resposta.indexOf(URL_MARKER);

    if (urlStart !== -1) {
      // Pega a string inteira a partir do in√≠cio da URL
      const fromUrl = resposta.substring(urlStart);

      // Encontra o √ļltimo %7D (fecha o JSON raiz da URL encoded)
      const lastIdx = fromUrl.lastIndexOf('%7D');

      if (lastIdx !== -1) {
        url_img = fromUrl.substring(0, lastIdx + 3);
      } else {
        // Fallback: pega at√© o primeiro espa√ßo ou quebra de linha
        const endMatch = fromUrl.match(/[\s\n]/);
        url_img = endMatch ? fromUrl.substring(0, endMatch.index) : fromUrl;
      }

      // Remove da resposta: tudo a partir do in√≠cio do bloco markdown
      // (que pode ser "![texto](" antes da URL) ou da pr√≥pria URL
      const mdBlockStart = resposta.lastIndexOf('![', urlStart);
      const cutFrom = mdBlockStart !== -1 && mdBlockStart > urlStart - 200
        ? mdBlockStart
        : urlStart;

      resposta = resposta.substring(0, cutFrom).trim();
    }

    // =========================
    // ūüßĻ LIMPEZA FINAL DA RESPOSTA
    // =========================
    resposta = resposta
      .replace(/\)\s*$/, '')       // remove ) solto no final
      .replace(/\s{3,}/g, '\n\n') // colapsa espa√ßos excessivos
      .trim();

    final = {
      resposta,
      url_img,
      tipo: "texto_processado"
    };
  }
} catch (error) {
  console.log('‚ĚĆ Erro:', error);
  final = {
    resposta: "Erro ao processar resposta",
    url_img: null,
    tipo: "erro_parse",
    detalhes: error.message
  };
}

// =========================
// ūüĒí GARANTE FORMATO FINAL
// =========================
final = {
  resposta: final.resposta || null,
  url_img: final.url_img || null,
  tipo: final.tipo || "fallback"
};

return [{ json: final }];

