// 1. Ordena as mensagens por data (mais recente ‚Üí mais antiga)
items.sort((a, b) => new Date(b.json.created_at) - new Date(a.json.created_at));

// 2. Pega apenas as √ļltimas 50 mensagens caso o hist√≥rico seja muito longo
const itensRecentes = items.slice(0, 5);

function formatarData(isoDate) {
  const d = new Date(isoDate);
  const dia = String(d.getDate()).padStart(2, '0');
  const mes = String(d.getMonth() + 1).padStart(2, '0');
  const ano = d.getFullYear();
  return `${dia}/${mes}/${ano}`;
}

const historico = [];

for (const item of itensRecentes) {
  const row = item.json;
  const dataFormatada = formatarData(row.created_at);

  // Processa mensagem do Usu√°rio
  if (row.mensagem_usuario && row.mensagem_usuario.toString().trim() !== "") {
    historico.push(`${dataFormatada} - Usu√°rio: ${row.mensagem_usuario.toString().trim()}`);
  }

  // Processa mensagem do Agente
  if (row.mensagem_agente && row.mensagem_agente.toString().trim() !== "") {
    // Caso a mensagem do agente venha como array/objeto de outro fluxo, converte para string
    const msgAgente = typeof row.mensagem_agente === 'string' 
      ? row.mensagem_agente 
      : JSON.stringify(row.mensagem_agente);

    historico.push(`${dataFormatada} - Agente: ${msgAgente.trim()}`);
  }
}

return [
  {
    json: {
      historico_conversa: historico.join("\n\n")
    }
  }
];

const raw = $input.first().json;

// Se vier encapsulado em body (caso do webhook)
const input = raw.body ?? raw;

// Fun√ß√£o auxiliar para evitar null
const safe = (value) => value ?? "";

// ------------------------------------
// CASO 1 - Payload simplificado (BMS)
// ------------------------------------
if (input.source === "BMS") {
  return [{
    origin: "BMS",
    chat_id: safe(input.chat_id || input.phone),
    message_id: safe(input.message_id),
    message_type: safe(input.message_type || "incoming"),
    phone: safe(input.phone),
    name: safe(input.name),
    type: safe(input.type || "text"),
    text: safe(input.text),
    media_url: safe(input.media_url)
  }];
}

// ------------------------------------
// CASO 2 - Payload Chatwoot
// ------------------------------------
const attachment = input.attachments?.[0] ?? null;

let type = "text";
let mediaUrl = "";

if (attachment) {
  type = attachment.file_type;
  mediaUrl = attachment.data_url ?? "";
}

return [{
  origin: "CHATWOOT",
  chat_id: safe(input.conversation?.id?.toString()),
  message_id: safe(input.source_id),
  message_type: safe(input.message_type || "incoming"),
  phone: safe(input.sender?.phone_number),
  name: safe(input.sender?.name),
  type: safe(type),
  text: safe(input.content),
  media_url: safe(mediaUrl)
}];

